const raw = msg.payload;

if (raw.rainfall === undefined || raw.water_level === undefined) {
    node.warn('[ENV] Payload tidak lengkap: ' + JSON.stringify(raw));
    return null;
}

const token = flow.get('IOT_JWT_TOKEN');
if (!token) {
    node.warn('[ENV] Token belum tersedia, payload masuk antrian.');
    flow.set('pendingQueue', (flow.get('pendingQueue') || []).concat([msg.payload]));
    return null;
}

msg.payload = {
    sensor_id   : raw.sensor_id   || 'NODE-RED-BRIDGE',
    rainfall    : parseFloat(raw.rainfall),
    water_level : parseFloat(raw.water_level)
};
msg.headers = {
    'Content-Type' : 'application/json',
    'Authorization': 'Bearer ' + token
};
msg.url = (env.get('API_GATEWAY_URL') || 'http://api-gateway:3000') + '/environment-data';

node.log('[ENV] rainfall=' + msg.payload.rainfall + ' water_level=' + msg.payload.water_level);
return msg;

const status = msg.statusCode;
if (status === 201 || status === 200) {
    node.log('[ENV OK] Data tersimpan.');
} else if (status === 401) {
    node.warn('[ENV] Token expired, force refresh.');
    flow.set('iot_token_exp', 0);
    flow.set('pendingQueue', (flow.get('pendingQueue') || []).concat([msg.payload]));
} else if (status === 429) {
    node.warn('[ENV] Rate limit, masuk antrian.');
    flow.set('pendingQueue', (flow.get('pendingQueue') || []).concat([msg.payload]));
} else {
    node.error('[ENV ERROR ' + status + '] ' + JSON.stringify(msg.payload));
}
return msg;

const queue = flow.get('pendingQueue') || [];
if (queue.length === 0) return null;
const item = queue.shift();
flow.set('pendingQueue', queue);
msg.payload = item;
msg.url = (env.get('API_GATEWAY_URL') || 'http://api-gateway:3000') + '/environment-data';
msg.headers = { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + (flow.get('IOT_JWT_TOKEN') || '') };
return msg;

const exp = flow.get('iot_token_exp') || 0;
if (Date.now() < exp - 60000) {
    node.status({ fill: 'green', shape: 'dot', text: 'token valid' });
    return null;
}
node.status({ fill: 'yellow', shape: 'ring', text: 'refreshing...' });
return msg;

const authUrl = env.get('AUTH_SERVICE_URL') || 'http://auth-service:3002';
msg.url = authUrl + '/oauth/token';
msg.method = 'POST';
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = {
    grant_type: 'client_credentials',
    client_id: env.get('IOT_CLIENT_ID') || 'iot-environment-device',
    client_secret: env.get('IOT_CLIENT_SECRET') || ''
};
return msg;

if (msg.statusCode === 200 && msg.payload && msg.payload.access_token) {
    flow.set('IOT_JWT_TOKEN', msg.payload.access_token);
    flow.set('iot_token_exp', Date.now() + (msg.payload.expires_in || 3600) * 1000);
    node.status({ fill: 'green', shape: 'dot', text: 'token refreshed' });
    node.log('[AUTH OK] Token refreshed');
} else {
    node.status({ fill: 'red', shape: 'ring', text: 'auth failed' });
    node.error('[AUTH FAILED] ' + JSON.stringify(msg.payload));
}
return null;
